{"name": "write_file", "arguments": {"path": "src/utils/retry.ts", "content": "export interface RetryOptions {
  maxRetries?: number;
  baseDelay?: number;
  maxDelay?: number;
  factor?: number;
  jitter?: boolean;
  retryOn?: (error: Error) => boolean;
}

const defaults: Required<RetryOptions> = {
  maxRetries: 3,
  baseDelay: 1000,
  maxDelay: 30000,
  factor: 2,
  jitter: true,
  retryOn: () => true,
};

/**
 * Retry an async function with exponential backoff.
 * Adds jitter by default to prevent thundering herd.
 */
export async function retry<T>(
  fn: () => Promise<T>,
  options: RetryOptions = {},
): Promise<T> {
  const opts = { ...defaults, ...options };
  let lastError: Error;

  for (let attempt = 0; attempt <= opts.maxRetries; attempt++) {
    try {
      return await fn();
    } catch (err) {
      lastError = err instanceof Error ? err : new Error(String(err));

      if (attempt === opts.maxRetries || !opts.retryOn(lastError)) {
        throw lastError;
      }

      const exponentialDelay = Math.min(
        opts.baseDelay * Math.pow(opts.factor, attempt),
        opts.maxDelay,
      );

      const delay = opts.jitter
        ? Math.random() * exponentialDelay
        : exponentialDelay;

      await new Promise((resolve) => setTimeout(resolve, delay));
    }
  }

  throw lastError!;
}
"}}
```

Created `src/utils/retry.ts`. Usage:

```typescript
import { retry } from './utils/retry';

const data = await retry(() => fetch('https://api.example.com/data'), {
  maxRetries: 5,
  baseDelay: 500,
  retryOn: (err) => err.message.includes('ECONNRESET'),
});
```

Key design decisions:
- **Jitter by default** — randomizes delay within the exponential window, preventing multiple clients from retrying in sync (thundering herd)
- **Configurable `retryOn`** — lets you retry only on specific errors (e.g., network failures but not 400s)
- **`maxDelay` cap** — prevents absurdly long waits on high retry counts

