{"content": "import { db } from '../database';
import { Order, OrderItem } from '../types';
import { sendEmail } from './email.service';
import { logger } from '../utils/logger';

export async function processOrder(order: Order) {
  // Validate items are in stock
  for (const item of order.items) {
    const { rows } = await db.query('SELECT quantity FROM inventory WHERE product_id = $1', [item.productId]);
    if (rows.length === 0) throw new Error(`Product ${item.productId} not found`);
    if (rows[0].quantity < item.quantity) throw new Error(`Insufficient stock for ${item.productId}`);
  }

  // Calculate totals
  let subtotal = 0;
  for (const item of order.items) {
    const { rows } = await db.query('SELECT price FROM products WHERE id = $1', [item.productId]);
    subtotal += rows[0].price * item.quantity;
  }
  const taxRate = order.state === 'CA' ? 0.0875 : order.state === 'NY' ? 0.08 : order.state === 'TX' ? 0.0625 : 0.05;
  const tax = subtotal * taxRate;
  const shipping = subtotal > 100 ? 0 : 9.99;
  const total = subtotal + tax + shipping;

  // Create order record
  const { rows: orderRows } = await db.query(
    'INSERT INTO orders (user_id, subtotal, tax, shipping, total, status) VALUES ($1, $2, $3, $4, $5, $6) RETURNING id',
    [order.userId, subtotal, tax, shipping, total, 'pending']
  );
  const orderId = orderRows[0].id;

  // Create line items
  for (const item of order.items) {
    await db.query(
      'INSERT INTO order_items (order_id, product_id, quantity, price) VALUES ($1, $2, $3, $4)',
      [orderId, item.productId, item.quantity, item.price]
    );
  }

  // Decrement inventory
  for (const item of order.items) {
    await db.query(
      'UPDATE inventory SET quantity = quantity - $1 WHERE product_id = $2',
      [item.quantity, item.productId]
    );
  }

  // Charge payment
  const paymentResult = await fetch('https://payments.example.com/charge', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${process.env.PAYMENT_KEY}` },
    body: JSON.stringify({ amount: total, currency: 'usd', customerId: order.paymentCustomerId }),
  });
  if (!paymentResult.ok) {
    await db.query('UPDATE orders SET status = $1 WHERE id = $2', ['payment_failed', orderId]);
    throw new Error('Payment failed');
  }
  await db.query('UPDATE orders SET status = $1 WHERE id = $2', ['paid', orderId]);

  // Send confirmation email
  await sendEmail({
    to: order.email,
    subject: `Order #${orderId} Confirmed`,
    body: `Your order total is $${total.toFixed(2)}. Thank you!`,
  });

  // Log
  logger.info({ orderId, total, items: order.items.length }, 'Order processed');

  return { orderId, total, status: 'paid' };
}
"}

